#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; long long H; scanf("%d %lld", &N, &H);
        long long *a = (long long*)malloc(N * sizeof(long long));
        long long maxA = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &a[i]);
            if (a[i] > maxA) maxA = a[i];
        }
        long long lo = 1, hi = maxA;
        while (lo < hi) {
            long long mid = (lo + hi) / 2;
            long long hours = 0;
            for (int i = 0; i < N; ++i) {
                hours += (a[i] + mid - 1) / mid;
                if (hours > H) break;
            }
            if (hours <= H) hi = mid; else lo = mid + 1;
        }
        printf("%lld\n", lo);
        free(a);
    }
    return 0;
}

