#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); H = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        lo, hi = 1, max(a)
        while lo < hi:
            mid = (lo + hi) // 2
            hours = 0
            for v in a:
                hours += (v + mid - 1) // mid
                if hours > H:
                    break
            if hours <= H:
                hi = mid
            else:
                lo = mid + 1
        out_lines.append(str(lo))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

